{
  "terms": [
    {
      "term": "Resistance",
      "simpleDefinition": "The total opposition to the flow of electric current within a circuit or component, measured in Ohms (Ω).",
      "anchor": "The 'friction' of the entire circuit that current must overcome.",
      "misconception": "Believing that only resistors have resistance, when in fact the wiring itself also opposes current."
    },
    {
      "term": "Resistivity",
      "simpleDefinition": "An inherent property of a specific material (like copper or aluminum) that determines how much it opposes current flow.",
      "anchor": "The 'DNA' of a material; it stays the same regardless of the material's shape or size.",
      "misconception": "Thinking resistivity changes if you make a wire longer; only the total resistance changes, not the material's resistivity."
    },
    {
      "term": "Voltage Drop",
      "simpleDefinition": "The loss of electrical pressure (potential) as current passes through a resistance.",
      "anchor": "The 'pressure drop' seen between the start and the end of a long hose.",
      "misconception": "Assuming voltage drop only occurs during a fault; it actually happens in every working circuit due to the resistance of the conductors."
    },
    {
      "term": "Ohm (Ω)",
      "simpleDefinition": "The unit of measurement for electrical resistance.",
      "anchor": "The standard 'score' for how hard a component fights against current.",
      "misconception": "Confusing the unit of resistance (Ohm) with the unit of resistivity (Ohm-metre)."
    },
    {
      "term": "Ohm-metre (Ωm)",
      "simpleDefinition": "The unit of measurement for resistivity.",
      "anchor": "The specific measurement used to compare the electrical quality of different raw materials.",
      "misconception": "Using this unit to describe a finished circuit; it is only for the material property itself."
    }
  ],
  "anchorPhrases": [
    "Resistance is the total opposition in the circuit.",
    "Resistivity is a fixed property of the material.",
    "Voltage drop is the energy used to push current through resistance.",
    "Resistivity is constant, but resistance changes with length and thickness."
  ],
  "misconceptionTargets": [
    "Resistance and resistivity are interchangeable terms.",
    "Voltage drop only happens when something is broken.",
    "Thicker wires have higher resistivity because they have more metal.",
    "Changing the length of a cable changes the resistivity of the copper inside."
  ]
}

